WITH input_poems(poet_slug, volume, title_zh, title_ko, category, meter, body_zh, status, quality, review_memo) AS (
  VALUES
    ('candidate-yuan-8036-5f8b-9444', 0, '沐浴子', NULL, '五言律詩', 5, '濯纓與濯足，
應欲任其真。
沐芳及浴蘭，
應務潔其身。
難洗耳中事，
易洗心上塵。
世間原自有，
常是洗心人。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00641","source_record_id":"CN-NT-CAT-00238","alias_record_ids":["CN-NT-CAT-00238"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%B2%90%E6%B5%B4%E5%AD%90_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '大道曲', NULL, '五言古詩', 5, '春風吹綉陌，
花滿帝鄉樹。
絲栁裊芳煙，
細用黃金縷。
分明湏盡是，
引蕩人心處。
車馬徃來塵，
儘結成紅霧。
樓上琵琶聲，
倚歌臨大路。
鄭重且休教，
放得春廻去。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00642","source_record_id":"CN-NT-CAT-00239","alias_record_ids":["CN-NT-CAT-00239"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%A4%A7%E9%81%93%E6%9B%B2_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '古意', NULL, '五言古詩', 5, '黃鵠巢高林，
黿鼉穴深淵。
且各得棲宿，
人獨胡不然。
釋耕於壠上，
妻子耘其前。
人笑苦畎畮，
何以遺子孫。
聊以一二答，
不可求備論。
人皆遺以危，
我獨遺以安。
春風吹布䄂，
雲滿鹿門山。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00643","source_record_id":"CN-NT-CAT-00240","alias_record_ids":["CN-NT-CAT-00240"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8F%A4%E6%84%8F_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '對酒', NULL, '五言古詩', 5, '漊者沈杯杓，
醇醨同一味。
狂風偃秋草，
蘭艾同一悴。
賢愚不同調，
薰蕕不同氣。
如何昧去就，
欲令為一致。
安得使賢愚，
各分於一噐。
安得使薰蕕，
各生於一地。
我志誠如斯，
未審化工意。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00644","source_record_id":"CN-NT-CAT-00241","alias_record_ids":["CN-NT-CAT-00241"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8D%E9%85%92_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '採蓮曲', NULL, '七言律詩', 7, '錦雲承露珠盤冷，
玉女珮環鳴玉井。
凝歌聲入天鏡來，
蘭橈攪碎蓬壺影。
弄香浮葉一何繁，
翠蓋霞幢不齊整。
可是芳心空自苦，
凌波無夣唯煙景。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00645","source_record_id":"CN-NT-CAT-00242","alias_record_ids":["CN-NT-CAT-00242"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%8E%A1%E8%93%AE%E6%9B%B2_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '紀夣', NULL, '七言古詩', 7, '衰草淡煙迷故壘，
情思迢迢似流水。
關山目斷鴈聲沉，
幾曲欄乾悶獨倚。
倚欄還憶早春時，
軟軟東風綻桃李。
青春如昨歲雲暮，
大抵人生如寄耳。
如何攜酒對明月，
一笑紅塵等白蟻。
歸來夣蝶惱莊周，
蝶去悠悠幾千里。
吟哦猶在月明下，
詩就清歡未能已。
舉手欲折桂枝去，
行入青天廣寒裏。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00646","source_record_id":"CN-NT-CAT-00243","alias_record_ids":["CN-NT-CAT-00243"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B4%80%E5%A4%A3_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '十四夜月', NULL, NULL, NULL, '秋風滾地來，
雲捲河漢淨。
遥觀東海底，
飛出黃金鏡。
雖未十分圓，
桂魄明且瑩。
停盃對清輝，
信筆成新詠。
慇懃舉酒囑姮娥，
休阻南樓來夜興。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00647","source_record_id":"CN-NT-CAT-00244","alias_record_ids":["CN-NT-CAT-00244"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8D%81%E5%9B%9B%E5%A4%9C%E6%9C%88_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '去婦怨', NULL, '七言律詩', 7, '最苦人生生別離，
怱怱輕別幾時歸。
紫簫吹落燕南月，
麗澤門開馬似飛。
雨情不定雲來去，
老鴈呌雲雲不住。
琵琶撥盡斷腸聲，
斷絃聲斷秋風暮。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00648","source_record_id":"CN-NT-CAT-00245","alias_record_ids":["CN-NT-CAT-00245"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8E%BB%E5%A9%A6%E6%80%A8_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '寄人', NULL, '五言律詩', 5, '空翠撲晴影，
輕黃著栁枝。
春風戀遊子，
渾似縱遊時。
除醉更無事，
憶君方有詩。
如何一片月，
兩地照相思。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00649","source_record_id":"CN-NT-CAT-00246","alias_record_ids":["CN-NT-CAT-00246"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%AF%84%E4%BA%BA_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春日即事', NULL, '五言律詩', 5, '遲日照青春，
遊風蕩紫宸。
雪霜無氣力，
桃李有精神。
幽思平欺酒，
閑愁自避人。
忘機殊不惡，
魚鳥者來馴。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00650","source_record_id":"CN-NT-CAT-00247","alias_record_ids":["CN-NT-CAT-00247"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%97%A5%E5%8D%B3%E4%BA%8B_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '老將', NULL, '五言律詩', 5, '結髪究韜畧，
驅馳四十年。
長征秦五嶺，
苦戰漢三邉。
萬死奮不顧，
一生今幸全。
雲臺無住處，
何日上凌煙。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00651","source_record_id":"CN-NT-CAT-00248","alias_record_ids":["CN-NT-CAT-00248"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%80%81%E5%B0%87_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '居庸闗', NULL, NULL, NULL, '秀㧞延天險，
寒盤萬古根。
東西日月，
南北限乾坤。
影落海山冷，
氣摇星鬥昏。
如何戰塵下，
荆棘暗重門。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00652","source_record_id":"CN-NT-CAT-00249","alias_record_ids":["CN-NT-CAT-00249"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B1%85%E5%BA%B8%E9%97%97_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '秋閨', NULL, '五言律詩', 5, '供給深閨怨，
秋聲又擣衣。
鴛鴦不獨宿，
燕子自雙飛。
塵暗芙蓉帳，
風褰翡翠幃。
馳心囑明月，
將此照金微。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00653","source_record_id":"CN-NT-CAT-00250","alias_record_ids":["CN-NT-CAT-00250"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E9%96%A8_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '詠雪二首', NULL, '五言古詩', 5, '樓曉倚欄乾，
天低欲壓闌。
削氷封嶽色，
飛席下雲端。
風陣連朝凍，
星鋩摇夜寒。
嶺梅應見怨，
何憚一來㸔。
日淡隔雲幕，
地虗鋪雪氊。
捲簾㸔不見，
如畫舊山川。
豈憶三杯酒，
能迴六月天。
一聲何處笛，
吹裂野梅邉。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00654","source_record_id":"CN-NT-CAT-00251","alias_record_ids":["CN-NT-CAT-00251"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A0%E9%9B%AA%E4%BA%8C%E9%A6%96_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '立春', NULL, '七言古詩', 7, '東帝施恩似恤貧，
嚴凝時節喚囘春。
未知和氣先歸栁，
便覺寒威不著人。
上苑三冬梅正發，
和林五月草初新。
世間均道唯春色，
春色年來也不均。
節物驚心苦見催，
一年還見兩春來。
臘寒自向人間盡，
春色却從天上迴。
乍暖栁條先易緑，
向陽花樹不難開。
高歌買斷西城酒，
更對東風盡此杯。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00655","source_record_id":"CN-NT-CAT-00252","alias_record_ids":["CN-NT-CAT-00252"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%AB%8B%E6%98%A5_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '清明', NULL, '七言律詩', 7, '寒食清明失舊期，
躊蹰搔首日沉西。
風生楊栁鴉先覺，
寒逼梧桐鳯不棲。
山色雪迷春意老，
鴈聲雲遏暮天低。
蘇門二月春光好，
好逐東風發馬蹄。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00656","source_record_id":"CN-NT-CAT-00253","alias_record_ids":["CN-NT-CAT-00253"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%B8%85%E6%98%8E_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '中秋對月', NULL, '七言律詩', 7, '銀燭煌煌十二衢，
冷金波浸酒仙居。
由來物外通明殿，
只是人間不夜珠。
玉女窻扉唯白曉，
素娥庭院更清虛。
桂花香陌無塵景，
坌入壺翁碧玉壺。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00657","source_record_id":"CN-NT-CAT-00254","alias_record_ids":["CN-NT-CAT-00254"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%B8%AD%E7%A7%8B%E5%B0%8D%E6%9C%88_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '欲雪', NULL, '七言律詩', 7, '癡雲洩洩復溶溶，
底事龍公睡起慵。
薄暮遥㸔巖岫失，
夜䦨空把鬥牛封。
徘徊天外心無定，
繚亂江頭色正濃。
寄與西風莫吹散，
梅花憔悴憶相逢。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00658","source_record_id":"CN-NT-CAT-00255","alias_record_ids":["CN-NT-CAT-00255"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%AC%B2%E9%9B%AA_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '送人', NULL, '七言律詩', 7, '是是非非儘自宜，
掀髯一笑且信眉。
休辭沉醉過終日，
縱得再歸來幾時。
極浦遥山遺別夢，
碧雲流水寄相思。
傷心去國頭如雪，
顦悴春風對栁枝。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00659","source_record_id":"CN-NT-CAT-00256","alias_record_ids":["CN-NT-CAT-00256"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%80%81%E4%BA%BA_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '早行', NULL, '七言律詩', 7, '窻外寒鷄唱五更，
翩翩征斾掛疎星。
百年身世情如夢，
半紙功名醉不醒。
欲吐半吞殘月淡，
似連還斷逺山青。
莫教草草生華髪，
消得幾回長短亭。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00660","source_record_id":"CN-NT-CAT-00257","alias_record_ids":["CN-NT-CAT-00257"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%97%A9%E8%A1%8C_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '寄隱者', NULL, '七言律詩', 7, '投老嘗期謝草萊，
有人懐抱待君開。
叩元要給談天口，
虛白元宜養聖胎。
鳯尾諾雖徴不起，
鶴頭書合召將來。
莫驚此㑹知何地，
認取黃金是舊臺。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00661","source_record_id":"CN-NT-CAT-00258","alias_record_ids":["CN-NT-CAT-00258"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%AF%84%E9%9A%90%E8%80%85_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5c48-5927-5747', 0, '佳人', NULL, '五言律詩', 5, '佳人回鶻裝，
衣帶內家香。
一曲飛龍引，
思君淚數行。
箜篌悲夜月，
眉黛落秋霜。
辛苦良家子，
年年向戰場。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00662","source_record_id":"CN-NT-CAT-00259","alias_record_ids":["CN-NT-CAT-00259"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%BD%B3%E4%BA%BA_(%E5%B1%88%E5%A4%A7%E5%9D%87)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6dee', 0, '佳人', NULL, '七言律詩', 7, '靜閱光隂惜歲華，
低頭無語倚牕紗。
新愁舊恨風前葉，
倦態羞容雨後花。
吟就白頭空自惜，
織成錦字向誰誇。
早知薄命難終愛，
何必生來願有家。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00663","source_record_id":"CN-NT-CAT-00260","alias_record_ids":["CN-NT-CAT-00260"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%BD%B3%E4%BA%BA_(%E9%BB%83%E6%B7%AE)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-91cb-51fd-53ef', 0, '佳人', NULL, '五言古詩', 5, '佳人年十八，
生長自皇都。
結髪嫁遠人，
謂是終身夫。
雞狗亦相將，
任逐東西徂。
西行過洞庭，
東竄寓穹廬。
豈料一朝餓，
顧盼及妾軀。
夫餓妾亦死，
妾賣夫得甦。
掩袂請速行，
東鄰有積儲。
紅顔賤如土，
鬥粟貴如珠。
但得前夫飽，
焉顧後夫痡。
夫痡齒復落，
猛虎踞庭除。
十日不相容，
苦勒解羅襦。
解襦兼解袒，
赤身哭向隅。
不願新人妾，
寧願舊人奴。
舊人與新人，
倉皇走道途。
少小學刺繡，
光綾三尺餘。
上有雙蝴蝶，
下有比目魚。
只今拭枯眼，
一片血模糊。
父母若早知，
不如棄溝渠。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00664","source_record_id":"CN-NT-CAT-00261","alias_record_ids":["CN-NT-CAT-00261"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%BD%B3%E4%BA%BA_(%E9%87%8B%E5%87%BD%E5%8F%AF)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春園', NULL, '七言律詩', 7, '勝事分明日月多，
金蓮川上愛涼蝸。
珍珠栁裊垂珠樹，
翡翠茵舒展翠莎。
虛白室常安樂土，
軟紅塵不到行窩。
索教粧㸃新春色，
分剩山花四五窠。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00665","source_record_id":"CN-NT-CAT-00262","alias_record_ids":["CN-NT-CAT-00262"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E5%9C%92_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '贈漁者', NULL, '七言律詩', 7, '蜃樓鰲殿對柴扉，
旋挽新荷補舊衣。
短笛有時渾落調，
曲鈎何計可忘機。
滄波萬頃淡煙合，
白鴈一聲黃葉稀。
回想渭濵人去後，
夕陽空滿釣魚磯。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00666","source_record_id":"CN-NT-CAT-00263","alias_record_ids":["CN-NT-CAT-00263"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%B4%88%E6%BC%81%E8%80%85_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '聽歌', NULL, '七言律詩', 7, '恰弄歌珠引玉清，
梁間已早暗塵驚。
流風迴結行雲住，
激水延緣潄霧生。
只道緜駒殊茹噎，
豈知王豹竟吞聲。
若為更得形容盡，
曲折浮沉怨慕情。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00667","source_record_id":"CN-NT-CAT-00264","alias_record_ids":["CN-NT-CAT-00264"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%81%BD%E6%AD%8C_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春懷', NULL, '七言律詩', 7, '碎擘桃花泛酒巵，
對春還詠惜春詩。
鶯能承意歌楊栁，
蝶觧含情舞柘枝。
世事儘它無定論，
醉懐却自有開時。
嵗寒亭下青松樹，
春去春來總不知。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00668","source_record_id":"CN-NT-CAT-00265","alias_record_ids":["CN-NT-CAT-00265"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%87%B7_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '松聲', NULL, '七言古詩', 7, '數間茅屋起雲峯，
明月天髙睡正濃。
乍覺夜傾千丈雨，
不知風度一山松。
人間拍岸驚秋浪，
海底喧天怒老龍。
洗盡生平塵垢慮，
浩然爽氣溢心胷。
蒼蒼欝欝本無情，
何處風來吹有聲。
四面迅雷平地起，
九江湍浪一時傾。
闗山夜靜蛟龍吼，
河漢秋髙鸞鳳鳴。
風定松閒無箇事，
喧天動地可來驚。
幽人耳凈聆錚錚，
一夕西風夢裏驚。
非玊非金非革木，
似琴似阮似秦箏。
夜閒拍枕三更雨，
秋冷喧天萬竈兵。
孤坐茅簷對明月，
一聲聲是自然聲。
巖聲何事韻錚錚，
風入寒梢鳥自驚。
七嶺夜寒篩漢月，
九霄霜冷奏秦箏。
歸心喚起陶元亮，
醉耳還醒阮歩兵。
擬賦新詩慵把筆，
劃然長嘯兩三聲。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00669","source_record_id":"CN-NT-CAT-00266","alias_record_ids":["CN-NT-CAT-00266"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%9D%BE%E8%81%B2_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春梅', NULL, '七言律詩', 7, '一夕西風糁玊塵，
曉來䇿蹇到江濵。
枝頭金蕾安排破，
雪裏氷姿凖偹春。
倚竹欲形閒態度，
臨岐微露舊精神。
此花底事年來早，
有意調羮近紫宸。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00670","source_record_id":"CN-NT-CAT-00267","alias_record_ids":["CN-NT-CAT-00267"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%A2%85_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '遊仙', NULL, '七言律詩', 7, '六銖仙帔映花朝，
䕶蹕痴龍膽氣驕。
五色雲車廻日馭，
九葩芝蓋抵星橋。
閒携鳳女批明月，
還縱鸞歌透紫霄。
半夜水精宮殿裏，
碧桃花下更聞簫。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00671","source_record_id":"CN-NT-CAT-00268","alias_record_ids":["CN-NT-CAT-00268"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%81%8A%E4%BB%99_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '宮怨', NULL, '七言律詩', 7, '脉脉慵拈鳯翼簫，
沈思陳事自無聊。
不惟只妬鶯聲巧，
且是嘗憎燕語嬌。
照膽光芒殊未歇，
守宮顔色若為消。
梅花獨自驚時節，
肯放春風到栁條。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00672","source_record_id":"CN-NT-CAT-00269","alias_record_ids":["CN-NT-CAT-00269"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%AE%AE%E6%80%A8_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '煬帝', NULL, '七言律詩', 7, '疊皷凝笳宴未闌，
戰塵回首滿人間。
南山翠竹長不起，
東海洪波流已乾。
寳駕陸沈池館盡，
錦帆星散水雲閒。
空餘仁夀宮前草，
遥接雷塘野樹寒。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00673","source_record_id":"CN-NT-CAT-00270","alias_record_ids":["CN-NT-CAT-00270"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%85%AC%E5%B8%9D_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '漢宮', NULL, '七言律詩', 7, '幻出壺天醉碧桃，
旋開雲竇挹瓊膏。
龍蟠燭影承香輦，
鳯擁簫聲繞赭袍。
織女機臨銀漢動，
捧盤人共玉蟾髙。
如何今日猗蘭殿，
吹盡雄風到野蒿。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00674","source_record_id":"CN-NT-CAT-00271","alias_record_ids":["CN-NT-CAT-00271"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%BC%A2%E5%AE%AE_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '宮詞', NULL, '七言律詩', 7, '玊輦聲沉不再過，
錦屏寒影夢如何。
露花凝夜香珠冷，
苔徑封春翠靨多。
怨燭淚乾遺曉月，
妖蓮心苦起秋波。
姮娥萬古青天上，
剰比人間受折魔。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00675","source_record_id":"CN-NT-CAT-00272","alias_record_ids":["CN-NT-CAT-00272"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%AE%AE%E8%A9%9E_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '閨怨', NULL, '五言絶句', 5, '惜春驚白日，
不到回心院。
合照妾人情，
也逐花隂轉。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00676","source_record_id":"CN-NT-CAT-00273","alias_record_ids":["CN-NT-CAT-00273"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%96%A8%E6%80%A8_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春晚', NULL, '五言絶句', 5, '雨餘芳草緑，
石盡野泉渾。
落日一聲笛，
斷腸人倚門。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00677","source_record_id":"CN-NT-CAT-00274","alias_record_ids":["CN-NT-CAT-00274"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%99%9A_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '夜坐', NULL, '五言絶句', 5, '香起深齋靜，
横琴夜更幽。
千巖風雨冷，
一夜鬼神愁。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00678","source_record_id":"CN-NT-CAT-00275","alias_record_ids":["CN-NT-CAT-00275"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%A4%9C%E5%9D%90_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '雜詠', NULL, '五言絶句', 5, '我雖不解事，
知時莫如我。
須為扇仁風，
吹滅權門火。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00679","source_record_id":"CN-NT-CAT-00276","alias_record_ids":["CN-NT-CAT-00276"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%9B%9C%E8%A9%A0_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '示子', NULL, '五言絶句', 5, '人皆縁禄富，
我獨以官貧。
富貴莫圖著，
恐他來逼人。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00680","source_record_id":"CN-NT-CAT-00277","alias_record_ids":["CN-NT-CAT-00277"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A4%BA%E5%AD%90_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '十六夜月', NULL, '五言絶句', 5, '月姊應吞怨，
無人冩所思。
柔情將綽態，
須是破瓜時。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00681","source_record_id":"CN-NT-CAT-00278","alias_record_ids":["CN-NT-CAT-00278"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8D%81%E5%85%AD%E5%A4%9C%E6%9C%88_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '即事', NULL, '五言絶句', 5, '青州少從事，
平原多督郵。
洞庭春色裏，
誰是醉鄉侯。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00682","source_record_id":"CN-NT-CAT-00279","alias_record_ids":["CN-NT-CAT-00279"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8D%B3%E4%BA%8B_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '閨思', NULL, NULL, NULL, '鴈陣驚秋信，
蛩吟襲夜幃。
河源應凍徹，
方憶搗征衣。
心事苧衣寛，
塵菱花暗。
春入水聲滑，
水涵春影澹。
問鴻鴻巳歸，
問花花不知。
却把鳳凰簫，
水精簾下吹。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00683","source_record_id":"CN-NT-CAT-00280","alias_record_ids":["CN-NT-CAT-00280"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%96%A8%E6%80%9D_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '西北', NULL, '七言絶句', 7, '不宜有怒徒傾地，
自伐無功可補天。
争忍競驅千萬騎，
又相馳突二三年。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00684","source_record_id":"CN-NT-CAT-00281","alias_record_ids":["CN-NT-CAT-00281"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%A5%BF%E5%8C%97_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '玉門關', NULL, '七言絶句', 7, '六合同風奉一君，
誰期貴介竟孤恩。
自從五夜傳金柝，
已早三年閉玉門。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00685","source_record_id":"CN-NT-CAT-00282","alias_record_ids":["CN-NT-CAT-00282"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%8E%89%E9%96%80%E9%97%9C_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '前出塞', NULL, '七言律詩', 7, '擬取安西襲玉關，
短兵鏖戰下臯蘭。
隂風勢挾天山雪，
凍徹河源徹底乾。
十年老將浮苴井，
萬里疲兵碎葉川。
傳督諸君傳詔令，
問何時到海西邊。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00686","source_record_id":"CN-NT-CAT-00283","alias_record_ids":["CN-NT-CAT-00283"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%89%8D%E5%87%BA%E5%A1%9E_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '銅雀臺', NULL, '七言絶句', 7, '銅雀臺荒野草花，
阿瞞無復示雄誇。
愁煙忍鎖西陵地，
向日須曾屬漢家。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00687","source_record_id":"CN-NT-CAT-00284","alias_record_ids":["CN-NT-CAT-00284"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%8A%85%E9%9B%80%E8%87%BA_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '白蓮池', NULL, '七言絶句', 7, '翠扇平遮罨畫樓，
玉盤傾露避蘭舟。
何如解語花長在，
花界長生殿裏頭。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00688","source_record_id":"CN-NT-CAT-00285","alias_record_ids":["CN-NT-CAT-00285"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%99%BD%E8%93%AE%E6%B1%A0_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '席上', NULL, '七言律詩', 7, '習飲醉鄉抛浩刼，
葆真靈液反天和。
方知世上閑滋味，
元比神仙不較多。
彩雲行雨陽臺暮，
羅襪生塵洛浦秋。
飛起一雙花上蝶，
晚風吹上玉搔頭。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00689","source_record_id":"CN-NT-CAT-00286","alias_record_ids":["CN-NT-CAT-00286"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B8%AD%E4%B8%8A_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '桃源', NULL, '七言律詩', 7, '洞仙情分與桃源，
儘與劉郎有舊縁。
兩手未為無用處，
不妨和月弄清泉。
驚風成陣花委塵，
白日如馳催老人。
只須深入桃源洞，
留住朱顔占住春。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00690","source_record_id":"CN-NT-CAT-00287","alias_record_ids":["CN-NT-CAT-00287"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%A1%83%E6%BA%90_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春意', NULL, '七言絶句', 7, '千里萬里遊子去，
一行兩行歸鴈來。
休倚髙樓起惆悵，
滿城桃李為春開。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00691","source_record_id":"CN-NT-CAT-00288","alias_record_ids":["CN-NT-CAT-00288"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%84%8F_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '春曉', NULL, '七言律詩', 7, '曉來雲捲四山晴，
睡起池塘春水平。
滿眼東風吹栁絮，
落花無語怨啼鶯。
瓊枝委露凝香雪，
澹月籠花浸麝塵。
喚起丁寧休喚起，
苧蘿山下浣紗人。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00692","source_record_id":"CN-NT-CAT-00289","alias_record_ids":["CN-NT-CAT-00289"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%9B%89_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '七夕', NULL, '七言古詩', 7, '一別相逢淚如雨，
不禁憔悴語相思。
佳期咫尺還知否，
明日傷情兩別離。
今日相逢明日離，
逡巡離合幾多時。
無情雲雨休遮隔，
人道相逢一歲期。
雨洗秋容秋氣清，
翠簾髙捲暮樓晴。
似含羞澁誰家女，
旋索金針拜月明。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00693","source_record_id":"CN-NT-CAT-00290","alias_record_ids":["CN-NT-CAT-00290"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%B8%83%E5%A4%95_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '詠雪', NULL, '七言絶句', 7, '碧玉壺天白玉塵，
十分添起月精神。
從今休作輕盈態，
學殺楊花不是春。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00694","source_record_id":"CN-NT-CAT-00291","alias_record_ids":["CN-NT-CAT-00291"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A0%E9%9B%AA_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '早梅', NULL, '七言絶句', 7, '一逕縈紆入草萊，
柴門雖設不曾開。
東風是洩春消息，
吹到梅花樹下來。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00695","source_record_id":"CN-NT-CAT-00292","alias_record_ids":["CN-NT-CAT-00292"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%97%A9%E6%A2%85_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '梅花引', NULL, '七言絶句', 7, '淡粧素服映氷肌，
香襲幽情暗有期。
漏泄美人心下事，
怕拈横玉倚風吹。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00696","source_record_id":"CN-NT-CAT-00293","alias_record_ids":["CN-NT-CAT-00293"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%A2%85%E8%8A%B1%E5%BC%95_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '牡丹', NULL, NULL, NULL, '問誰養牡丹芽，
枕天津第一家。
不枉得輸青帝力，
見開知是異凡花。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00697","source_record_id":"CN-NT-CAT-00294","alias_record_ids":["CN-NT-CAT-00294"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%89%A1%E4%B8%B9_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '芍藥', NULL, '七言絶句', 7, '楊家一捻紅嬌潤，
與醉西施較等差。
倘使紅粧無藉在，
寳冠須也是閒花。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00698","source_record_id":"CN-NT-CAT-00295","alias_record_ids":["CN-NT-CAT-00295"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%8A%8D%E8%97%A5_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '楊花', NULL, NULL, NULL, '遊人枉自怨年華，
斷送春風是此花。
難管領，
一天晴雪誰家。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00699","source_record_id":"CN-NT-CAT-00296","alias_record_ids":["CN-NT-CAT-00296"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%A5%8A%E8%8A%B1_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '秋鶯', NULL, '七言絶句', 7, '落盡羣英一見愁，
只因天地兩經秋。
流鶯不道春光老，
剗地如今調舌頭。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00700","source_record_id":"CN-NT-CAT-00297","alias_record_ids":["CN-NT-CAT-00297"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E9%B6%AF_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '覽鏡', NULL, '七言絶句', 7, '月讓清光日讓圓，
翠鸞伏背浸瓊筵。
明為富貴自來逼，
誰不更教長少年。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00701","source_record_id":"CN-NT-CAT-00299","alias_record_ids":["CN-NT-CAT-00299"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%A6%BD%E9%8F%A1_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '答客問', NULL, NULL, NULL, '客有調予者曰：
「閲君《獨醉園賦》，
君自謂『蓮社上逰』，
又為『獨醉癡仙』。
仙佛殊教，
君之所謂，
必有説矣。
」因以是答。
是佛盡居安樂國，
無仙不住沒愁鄉。
聽教共獻天花供，
更管清名分外香。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00702","source_record_id":"CN-NT-CAT-00300","alias_record_ids":["CN-NT-CAT-00300"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%AD%94%E5%AE%A2%E5%95%8F_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '少年行', NULL, '七言絶句', 7, '燕燕鶯鶯滿鳯城，
好花時節更闗情。
自從雙鯉消沈後，
惆悵春流越淺清。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00703","source_record_id":"CN-NT-CAT-00301","alias_record_ids":["CN-NT-CAT-00301"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%91%E5%B9%B4%E8%A1%8C_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '讀史', NULL, NULL, NULL, '瓊枝秀出迷春洞，
璧月光生媚玉樓。
傾國佳人足傾國，
無愁天子得無愁。
軒轅事業與唐虞，
搃是規模後世書。
後玩兵除德讓，
不知終古更何如？', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00704","source_record_id":"CN-NT-CAT-00302","alias_record_ids":["CN-NT-CAT-00302"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%AE%80%E5%8F%B2_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '惜別', NULL, '七言絶句', 7, '憶昔相逢各少年，
幾臨風月醉華筵。
悠悠別後空回首，
風起楊花雪滿天。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00705","source_record_id":"CN-NT-CAT-00303","alias_record_ids":["CN-NT-CAT-00303"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%83%9C%E5%88%AB_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '漫興', NULL, '七言絶句', 7, '誰曽煎得膠黏日，
誰解拽將䋲繫風。
豈道花枝與人面，
大都都得幾時紅。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00706","source_record_id":"CN-NT-CAT-00304","alias_record_ids":["CN-NT-CAT-00304"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%BC%AB%E8%88%88_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '信筆', NULL, '七言絶句', 7, '自從得踐老成域，
曽不更登年少塲。
空賦棲烏夜啼曲，
可憐誰是賀知章。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00707","source_record_id":"CN-NT-CAT-00305","alias_record_ids":["CN-NT-CAT-00305"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%BF%A1%E7%AD%86_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '感懷', NULL, '七言絶句', 7, '屈盡人間薄宦情，
千鍾從此一毫輕。
人心直要平如水，
水面風來更不平。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00708","source_record_id":"CN-NT-CAT-00306","alias_record_ids":["CN-NT-CAT-00306"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%84%9F%E6%87%B7_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '所思', NULL, '七言絶句', 7, '望外青山斷復連，
望中明月缺還圓。
碧雲暮合横長笛，
目送歸鴻不盡天。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00709","source_record_id":"CN-NT-CAT-00307","alias_record_ids":["CN-NT-CAT-00307"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%89%80%E6%80%9D_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '對酒吟', NULL, '七言絶句', 7, '莫勞鄒律喚春回，
雪盡北山空自來。
還笑獨醒成底事，
壯懷須對酒杯開。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00710","source_record_id":"CN-NT-CAT-00308","alias_record_ids":["CN-NT-CAT-00308"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8D%E9%85%92%E5%90%9F_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '金樂歌', NULL, '七言絶句', 7, '百花氣色雖千變，
萬刼光陰只一般。
金樂既和行樂在，
我將天地結心懽。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00711","source_record_id":"CN-NT-CAT-00309","alias_record_ids":["CN-NT-CAT-00309"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%87%91%E6%A8%82%E6%AD%8C_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-8036-5f8b-9444', 0, '征婦怨', NULL, '七言絶句', 7, '錦織回文織過秋，
千絲萬縷織成愁。
停梭心口私相問，
誰在凌煙閣上頭。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00712","source_record_id":"CN-NT-CAT-00310","alias_record_ids":["CN-NT-CAT-00310"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%BE%81%E5%A9%A6%E6%80%A8_(%E8%80%B6%E5%BE%8B%E9%91%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '漁', NULL, NULL, NULL, '江北清波細浪，
溪南暮雨西風。
短笛黃蘆花外，
扁舟紅蓼叢中。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00713","source_record_id":"CN-NT-CAT-00311","alias_record_ids":["CN-NT-CAT-00311"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%BC%81_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '下第述懷', NULL, '五言古詩', 5, '匠石屢不顧，
定匪明堂材。
淵客屢不採，
定匪明月胎。
十年三棄置，
中情空自哀。
傷哉吾道非，
豈乏乾時媒。
歎彼行役苦，
畏茲年鬢催。
進退兩躑躅，
坐立空徘徊。
升鬥豈吾志，
結念居南陔。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00714","source_record_id":"CN-NT-CAT-00312","alias_record_ids":["CN-NT-CAT-00312"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%B8%8B%E7%AC%AC%E8%BF%B0%E6%87%B7_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '戰城南', NULL, NULL, NULL, '戰城南，
死城北，
枯骨纍纍棄路側。
為我謂烏，
逰魂不歸。
臭腐將焉用烏，
飼汝安足悲。
隂雲漠漠烏，
寒雨瀟瀟。
黃昏古城下，
新聲號咷。
陽九厄，
戰城南，
空褁革。
七尺㣲軀我不惜，
老死蓬蒿竟何益。
願為忠臣，
忠臣誠可為。
茫茫穹廬，
掩骼為誰？', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00715","source_record_id":"CN-NT-CAT-00313","alias_record_ids":["CN-NT-CAT-00313"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%88%B0%E5%9F%8E%E5%8D%97_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '秋風辭', NULL, NULL, NULL, '秋風搖落兮，
草木變衰。
白雲繚繞兮，
鴻鴈聲悲。
蘭為佩兮，
芙蓉為裳。
彼君子兮，
天一方。
鼓桂櫂兮，
度橫塘。
明星爛兮，
露為霜。
歌聲沸兮，
夜未央。
誓與君兮，
永不忘。
人生歡㑹兮，
安可常？', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00716","source_record_id":"CN-NT-CAT-00314","alias_record_ids":["CN-NT-CAT-00314"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E9%A2%A8%E8%BE%AD_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '飛龍篇', NULL, '五言古詩', 5, '海上三神山，
中為僊人居。
金樓髙崔嵬，
玉堂結綺疏。
朝乗飛龍去，
翱翔登鼎湖。
騁風周八極，
飄飄凌紫虛。
安期同遨逰，
八公相為徒。
看日扶桑巔，
采藥崑崙區。
桑田有變遷，
人世多榮枯。
安得乞靈藥，
蜕此凡濁軀。
一朝生毛羽，
白日昇天衢。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00717","source_record_id":"CN-NT-CAT-00315","alias_record_ids":["CN-NT-CAT-00315"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%A3%9B%E9%BE%8D%E7%AF%87_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '悲愁歌', NULL, NULL, 7, '我之生兮在深宮，
嗟薄命兮事逺戎。
烏孫老兮語不通，
征塵起兮多悲風。
望故土兮心忡忡，
羨黃鵠兮淚無窮。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00718","source_record_id":"CN-NT-CAT-00316","alias_record_ids":["CN-NT-CAT-00316"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%82%B2%E6%84%81%E6%AD%8C_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '落葉哀蟬曲', NULL, NULL, NULL, '西風兮吹襟，
蟬聲兮滿林。
古砌靜而葉落，
淒然感乎予心。
憶美人於閨房兮，
方歛袂而沉吟。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00719","source_record_id":"CN-NT-CAT-00317","alias_record_ids":["CN-NT-CAT-00317"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%90%BD%E8%91%89%E5%93%80%E8%9F%AC%E6%9B%B2_(%E5%BE%90%E7%86%A5)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f90-71a5', 0, '野田黃雀行', NULL, '五言古詩', 5, '朝來歩野田，
